import{_ as o,o as r,c as a,ag as e}from"./chunks/framework.Bgwu_dgr.js";const p=JSON.parse('{"title":"소개","description":"","frontmatter":{},"headers":[],"relativePath":"overview/index.md","filePath":"overview/index.md","lastUpdated":null}'),n={name:"overview/index.md"};function s(i,t,l,g,h,u){return r(),a("div",null,[...t[0]||(t[0]=[e('<h1 id="소개" tabindex="-1">소개 <a class="header-anchor" href="#소개" aria-label="Permalink to &quot;소개&quot;">​</a></h1><h2 id="발표-개요" tabindex="-1">발표 개요 <a class="header-anchor" href="#발표-개요" aria-label="Permalink to &quot;발표 개요&quot;">​</a></h2><p>2025년 12월 8일, AI Engineer 컨퍼런스의 무대에서 한 편의 짧은 발표가 공개되었다. Anthropic의 두 엔지니어 Barry Zhang과 Mahesh Murag이 16분 동안 던진 메시지는 명확하고 도발적이었다. <strong>&quot;에이전트를 그만 만들고, 스킬(Skills)을 만들어라.&quot;</strong></p><p>발표는 단순한 신기술 소개가 아니다. AI 업계 전체가 &quot;커스텀 에이전트&quot;를 경쟁적으로 찍어내고 있는 시점에, 그 방향이 틀렸다고 선언하는 전환점이다. 그 대안으로 제시된 것이 바로 <strong>Agent Skills</strong> -- 폴더에 담긴 마크다운과 스크립트로 구성된, 지극히 단순한 구조다.</p><h2 id="발표의-핵심-주장" tabindex="-1">발표의 핵심 주장 <a class="header-anchor" href="#발표의-핵심-주장" aria-label="Permalink to &quot;발표의 핵심 주장&quot;">​</a></h2><p>Zhang과 Murag이 보기에 오늘날의 에이전트는 <strong>지능은 있지만 전문성이 없다</strong>. 세무 코드를 처리해야 하는 상황을 상상해보자. 300 IQ의 수학 천재(Mahesh)와 세무 경력 20년의 전문가(Barry) 중 누구에게 맡길 것인가? 대부분은 Barry를 택한다. 에이전트에게 필요한 것은 더 많은 지능이 아니라, 문제 영역에 대한 <strong>축적된 절차적 지식</strong>이다.</p><p>그 지식을 담는 그릇이 바로 스킬이다. 스킬은 거창한 프레임워크가 아니다. 폴더 하나, 그 안의 <code>SKILL.md</code> 파일 하나로 시작할 수 있다. Git으로 버전 관리하고, Google Drive나 ZIP으로 공유할 수 있다. 개발자가 아닌 법무, 회계, 리크루팅 담당자도 만들 수 있다.</p><h2 id="발표자는-누구인가" tabindex="-1">발표자는 누구인가 <a class="header-anchor" href="#발표자는-누구인가" aria-label="Permalink to &quot;발표자는 누구인가&quot;">​</a></h2><p><strong>Barry Zhang</strong>은 Anthropic의 엔지니어로, Agent Skills 프로젝트의 핵심 구축자 중 한 명이다. 발표에서 그는 &quot;세무 전문가 Barry&quot; 역할을 직접 맡아 농담 섞인 분위기로 전문성의 가치를 설명한다.</p><p><strong>Mahesh Murag</strong> 역시 Anthropic의 엔지니어로, Skills 시스템의 기술적 설계와 생태계 구축에 관여했다. 발표자 스스로를 &quot;300 IQ 수학 천재&quot;에 비유하면서도 &quot;세무 문제에서는 Barry에게 지겠다&quot;고 인정하는 장면이 인상적이다.</p><p>두 엔지니어는 AI 업계 리더의 거창한 선언이 아니라, 수개월간 Claude Code와 Skills 시스템을 직접 만들어온 <strong>현장 엔지니어의 관찰</strong>로 발표를 채운다.</p><h2 id="발표의-맥락" tabindex="-1">발표의 맥락 <a class="header-anchor" href="#발표의-맥락" aria-label="Permalink to &quot;발표의 맥락&quot;">​</a></h2><p>이 발표가 중요한 이유는 시점이다. 2025년은 &quot;에이전트의 해&quot;였다. 수많은 스타트업이 도메인별 커스텀 에이전트를 출시했고, 프레임워크들이 난립했다. 그러나 Anthropic이 Claude Code를 만들면서 관찰한 것은 다른 결론이었다. <strong>에이전트의 아키텍처는 사실 보편적이다.</strong> 서로 다른 사용 사례라고 여겨진 것들이 실은 하나의 범용 에이전트 + 도메인 스킬의 조합으로 더 잘 작동했다.</p><p>Anthropic은 2025년 10월 Agent Skills를 공식 출시했고, 5주 만에 수천 개의 스킬이 생성되었다. 이 발표는 그 경험을 기반으로 업계 전체에 방향 전환을 제안하는 자리다.</p><h2 id="다루는-주제들" tabindex="-1">다루는 주제들 <a class="header-anchor" href="#다루는-주제들" aria-label="Permalink to &quot;다루는 주제들&quot;">​</a></h2><p>발표는 다음과 같은 주제를 폭넓게 다룬다:</p><ul><li><strong>전문성의 공백</strong> -- 왜 똑똑한 에이전트도 실무에서는 부족한가</li><li><strong>스킬이란 무엇인가</strong> -- 폴더 하나로 시작하는 절차적 지식의 패키지</li><li><strong>코드, 세계와의 인터페이스</strong> -- 왜 코드가 범용 도구인가</li><li><strong>점진적 공개(Progressive Disclosure)</strong> -- 수천 개 스킬을 지원하면서 컨텍스트를 보호하는 법</li><li><strong>스킬 생태계</strong> -- 5주 만에 수천 개, 기초/서드파티/엔터프라이즈 세 갈래</li><li><strong>수렴하는 에이전트 아키텍처</strong> -- 에이전트 루프, 런타임, MCP, 스킬의 조합</li><li><strong>지속 학습과 집단 지식</strong> -- 조직의 암묵지를 스킬로 물질화하기</li></ul><p>각 주제에 대한 상세 분석은 <a href="/youtube-do-not-build-agents/topics/">주제별 분석</a> 페이지에서 확인할 수 있다.</p><hr><div class="info custom-block"><p class="custom-block-title">영상 정보</p><ul><li><strong>제목</strong>: &quot;Don&#39;t Build Agents, Build Skills Instead&quot;</li><li><strong>발표자</strong>: Barry Zhang &amp; Mahesh Murag (Anthropic)</li><li><strong>컨퍼런스</strong>: AI Engineer (Code Summit)</li><li><strong>공개일</strong>: 2025. 12. 8.</li><li><strong>길이</strong>: 약 16분</li></ul></div>',20)])])}const c=o(n,[["render",s]]);export{p as __pageData,c as default};
